INSERT INTO cm_topo_draw_tool ( user_id, grp_no, dev_kind1, dev_kind2, pos_x, pos_y, width, height, fill_color, fill_opacity, stroke_color, stroke_opacity, stroke_width, corner_radius, font_size, font_weight, text_anchor, text_content, rx, ry, sort_idx, text_area_content, font_distance, rotation ) SELECT user_id, #{addGrpNo}, dev_kind1, dev_kind2, pos_x, pos_y, width, height, fill_color, fill_opacity, stroke_color, stroke_opacity, stroke_width, corner_radius, font_size, font_weight, text_anchor, text_content, rx, ry, (SELECT COALESCE(MAX(sort_idx), 0) + 1 FROM cm_topo_draw_tool WHERE grp_no = #{addGrpNo} AND user_id = ), text_area_content, font_distance, rotation FROM cm_topo_draw_tool A WHERE draw_no = #{item.drawNo} AND user_id = ;
