mapper.select:
SELECT A.mng_no AS "mngNo", B.item_no AS "itemNo"
FROM cm_dev10 A
    LEFT JOIN (
        SELECT item_no, mng_no
        FROM   cm_topo_item
        WHERE  grp_no = #{grpNo}
        AND    dev_kind1 != 'GRP'
    ) B ON A.mng_no = B.mng_no
WHERE dev_ip = #{devIp}
